sql:
SELECT lesson_name, duration
FROM lessons
WHERE duration >= 30 AND prerequisites IS NOT NULL AND prerequisites != '';

SELECT lesson_name, duration
FROM lessons
ORDER BY duration DESC;

SELECT version_number, release_date
FROM course_versions
ORDER BY release_date DESC;

external_knowledge:
- "shining stars" refers to users who are performing well in the course;
- "completion rate" is the percentage of lessons a user has completed out of the total lessons in the version;
- "average feedback rating" is the mean rating given by users for the lessons they have completed.

sql:
SELECT lesson_name, description
FROM lessons
WHERE duration > (SELECT AVG(duration) FROM lessons);

SELECT COUNT(DISTINCT user_id) AS total_users
FROM lesson_progress
WHERE progress_percentage = 100;

external_knowledge:
- 'Sown the seeds of knowledge' refers to users who have completed at least one lesson (progress percentage = 100%);
- 'Marking their journey' refers to users who have created at least one bookmark;
- 'Depth of their engagement' is calculated as the total time spent by users on lessons divided by the total duration of all lessons, expressed as a percentage.

sql:
SELECT lesson_id, COUNT(bookmark_id) AS total_bookmarks
FROM bookmark
GROUP BY lesson_id;

SELECT COUNT(*) 
FROM lesson_versions 
WHERE updated_date > '2023-01-01';

SELECT version_id, COUNT(lesson_id) AS Total_Lessons_Per_Version
FROM lessons
GROUP BY version_id;

SELECT user_id, SUM(progress_percentage) AS total_progress
FROM lesson_progress
GROUP BY user_id;

SELECT COUNT(DISTINCT user_id) AS total_users
FROM lesson_progress
WHERE progress_percentage > 80;

external_knowledge:
- "diligent learners" refers to users who have completed their lessons with a progress percentage of 100%;
- "surpassed the average effort" refers to users who have spent more time on their completed lessons than the average time spent by all users;
- "fully completing their lessons" means the `completed_date` is not null and `progress_percentage` is 100%.

sql:
SELECT user_id, lesson_id, bookmark_date
FROM bookmark
WHERE position > 300;

external_knowledge:
- "fully mastered" refers to lessons where the `progress_percentage` is 100%;
- "most dedicated scholars" refers to users with the highest `time_spent` in each lesson, specifically those ranked 1st;
- "mark their path with bookmarks" refers to the number of bookmarks created by the user.

- 'longer lessons' refers to lessons with a duration greater than the average duration of all lessons;
- 'surpassed the average completion rate' means the learner has completed more lessons than the average number of lessons completed by all users;
- 'spent more time on the lesson than the average user' means the learner spent more time on the lesson than the average time spent by all users on any lesson.

sql:
SELECT COUNT(DISTINCT user_id) 
FROM lesson_progress 
WHERE lesson_id = 1 AND progress_percentage >= 80;

external_knowledge:
- 'Completed more than one lesson' means the user has finished multiple lessons in the system;
- 'Shared their thoughts' refers to providing feedback or ratings for the lessons;
- 'Gardener who has nurtured multiple flowers' is a metaphor for a user who has engaged deeply with the platform by completing and reviewing multiple lessons.

sql:
SELECT user_id, progress_percentage
FROM lesson_progress
WHERE lesson_id = 1 AND progress_percentage > 50;
